def field(source_id: str, raw: str, known: str, reads: str, usage: str, retained: str, norm: str, fastapi: str, mcp: str, frontend: str, conv: str, proposed: str, metric: str, caveat: str, files: list[str], symbol: str, confidence: str, dropped_status: str, reason_cat: str, reason_detail: str, decision_status: str, priority: str, blockers: list[str]) -> dict[str, Any]:
    derived = []
    normalized_name = norm
    if norm == 'source_timestamp/delay_seconds derived':
        derived = ['source_timestamp', 'delay_seconds']
        normalized_name = ''
    elif norm == 'source_timestamp derived':
        derived = ['source_timestamp']
        normalized_name = ''
    return {'source_id': source_id, 'raw_field_name': raw, 'raw_field_known': known, 'current_parser_reads_field': reads, 'current_parser_usage': usage, 'retained_as_independent_normalized_field': retained, 'normalized_field_name': normalized_name, 'derived_normalized_fields': derived, 'exposed_fastapi': fastapi, 'exposed_mcp': mcp, 'exposed_frontend': frontend, 'exposed_conversation_context': conv, 'proposed_normalized_field_name': proposed, 'deterministic_metric_enabled': metric, 'semantic_caveat': caveat, 'evidence_files': files, 'evidence_symbol_or_function': symbol, 'evidence_confidence': confidence, 'dropped_status': dropped_status, 'dropped_reason_category': reason_cat, 'dropped_reason_detail': reason_detail, 'dropped_decision_evidence': '; '.join(files + [symbol]), 'dropped_decision_status': decision_status, 'reintroduction_priority': priority, 'reintroduction_blockers': blockers}
