def validate(data: dict[str, Any]) -> None:
    errors: list[str] = []
    source_by_id = {s['source_id']: s for s in data['source_families']}
    forbidden_key = 'dropped' + '_after_fetch'
    if forbidden_key in json.dumps(data, ensure_ascii=False):
        errors.append('deprecated drop-state key/value present in generated data')
    for s in data['source_families']:
        if s['evidence_status'] not in EVIDENCE_STATUS:
            errors.append(f"bad evidence_status:{s['source_id']}")
        if s['source_availability_status'] not in AVAILABILITY_STATUS:
            errors.append(f"bad availability:{s['source_id']}")
        if not set(s['runtime_exposure_status']).issubset(RUNTIME_STATUS):
            errors.append(f"bad runtime status:{s['source_id']}")
        if s['evidence_status'] == 'credential_gated_provider' and s['source_availability_status'] == 'implemented_normalized_now':
            errors.append(f"credential implemented contradiction:{s['source_id']}")
        if s['evidence_status'] == 'catalogued_candidate' and any((x.startswith('exposed_in_') for x in s['runtime_exposure_status'])):
            errors.append(f"candidate exposed contradiction:{s['source_id']}")
        for c in s.get('evidence_claims', []):
            if c['confidence'] not in CONFIDENCE or not c['evidence_files']:
                errors.append(f"bad claim:{s['source_id']}:{c.get('claim_id')}")
    for r in data['field_inventory']:
        if r['evidence_confidence'] not in CONFIDENCE:
            errors.append(f"bad confidence:{r['source_id']}:{r['raw_field_name']}")
        if 'dropped_status' not in r or not isinstance(r.get('dropped_status'), str) or (not r.get('dropped_status')):
            errors.append(f"missing single dropped_status:{r.get('source_id')}:{r.get('raw_field_name')}")
        if r['retained_as_independent_normalized_field'] == 'no' and r['normalized_field_name'] and ('derived' not in r['normalized_field_name']):
            errors.append(f"unretained has normalized name:{r['source_id']}:{r['raw_field_name']}")
        if r['current_parser_reads_field'] == 'no' and 'not read' not in r['current_parser_usage'] and ('source is not' not in r['current_parser_usage']):
            errors.append(f"unread active usage:{r['source_id']}:{r['raw_field_name']}")
        if r['dropped_status'] not in DROPPED_STATUS:
            errors.append(f"bad dropped_status:{r['source_id']}:{r['raw_field_name']}")
        exposure_values = [r.get('exposed_fastapi'), r.get('exposed_mcp'), r.get('exposed_frontend'), r.get('exposed_conversation_context')]
        exposure_yes = sum(1 for value in exposure_values if value == 'yes')
        if r['dropped_status'] == 'parsed_but_not_exposed' and exposure_yes != 0:
            errors.append(f"parsed_but_not_exposed has exposure:{r['source_id']}:{r['raw_field_name']}")
        if r['dropped_status'] == 'parsed_retained_partially_exposed' and not (0 < exposure_yes < len(exposure_values)):
            errors.append(f"partial exposure status mismatch:{r['source_id']}:{r['raw_field_name']}")
        if r['dropped_reason_category'] not in DROP_REASON:
            errors.append(f"bad drop reason:{r['source_id']}:{r['raw_field_name']}")
        if r['dropped_decision_status'] not in DROP_DECISION:
            errors.append(f"bad drop decision:{r['source_id']}:{r['raw_field_name']}")
        if r['reintroduction_priority'] not in PRIORITY:
            errors.append(f"bad priority:{r['source_id']}:{r['raw_field_name']}")
        if r['dropped_status'] == 'not_dropped' and r['dropped_reason_category'] not in {'not_applicable', ''}:
            errors.append(f"not_dropped reason:{r['source_id']}:{r['raw_field_name']}")
        if r['dropped_decision_status'] == 'explicit_repo_decision' and (not r['evidence_files']):
            errors.append(f"explicit no evidence:{r['source_id']}:{r['raw_field_name']}")
        if r['dropped_reason_category'] == 'accidental_or_unexplained' and r['dropped_decision_status'] != 'no_clear_decision_found':
            errors.append(f"unexplained decision mismatch:{r['source_id']}:{r['raw_field_name']}")
        if source_by_id[r['source_id']]['evidence_status'] == 'credential_gated_provider' and r['dropped_status'] == 'fetched_but_not_parsed':
            errors.append(f"credential fetched contradiction:{r['source_id']}:{r['raw_field_name']}")
        if not source_by_id[r['source_id']]['runtime_integrated'] and r['dropped_status'] in {'fetched_but_not_parsed', 'parsed_but_not_exposed', 'consumed_not_retained'}:
            errors.append(f"nonruntime runtime-dropped:{r['source_id']}:{r['raw_field_name']}")
        if r['reintroduction_priority'] == 'M7A_high' and source_by_id[r['source_id']]['evidence_status'] != 'validated_runtime_source':
            errors.append(f"M7A nonruntime:{r['source_id']}:{r['raw_field_name']}")
    if errors:
        raise SystemExit('inventory consistency failed:\n' + '\n'.join(errors))

def write_csv(path: Path, rows: list[dict[str, Any]]) -> None:
    keys: list[str] = []
    for row in rows:
        for key in row:
            if key not in keys:
                keys.append(key)
    with path.open('w', encoding='utf-8', newline='') as f:
        writer = csv.DictWriter(f, fieldnames=keys, lineterminator='\n')
        writer.writeheader()
        for row in rows:
            writer.writerow({k: json.dumps(v, ensure_ascii=False) if isinstance(v, (list, dict)) else v for k, v in row.items()})

def table(rows: list[dict[str, Any]], cols: list[str]) -> str:
    out = ['| ' + ' | '.join(cols) + ' |', '|' + '|'.join(['---'] * len(cols)) + '|']
    for row in rows:
        out.append('| ' + ' | '.join((str(row.get(c, '')).replace('|', '\\|') for c in cols)) + ' |')
    return '\n'.join(out)

def markdown(data: dict[str, Any]) -> str:
    counts = Counter((s['evidence_status'] for s in data['source_families']))
    lines = ['# Validated Endpoint Data Capability Inventory', '', '## Executive summary', '', 'This inventory includes validated runtime sources, validated contracts/probes, validated historical workbench sources, catalogued candidates, and credential-gated providers. Not every listed source family is a validated usable endpoint. The current product works, but the exposed live context remains thin because several raw fields are known while the parser/normalizer/consumers retain only selected facts. This report separates source availability, parser consumption, normalized retention, and consumer exposure before M7A/M7B/M7C/M7D/M7E implementation.', '', f'Evidence-status counts: {dict(counts)}', '', '## Source-family summary', '', table([{'source_id': s['source_id'], 'evidence_status': s['evidence_status'], 'availability_status': s['source_availability_status'], 'authority_class': s['authority_class'], 'timing_class': s['timing_class'], 'runtime_integrated': s['runtime_integrated'], 'candidate_milestone': s['candidate_milestone']} for s in data['source_families']], ['source_id', 'evidence_status', 'availability_status', 'authority_class', 'timing_class', 'runtime_integrated', 'candidate_milestone']), '', '## Source taxonomy summary', '', table([{'category': k, 'source_ids': ', '.join(v)} for k, v in data['source_taxonomy_summary'].items()], ['category', 'source_ids']), '', '## Current architecture map', '', '- Local canonical context: M5F local artifacts are read through FastAPI, frontend, MCP, and conversation context.', '- Live bounded observation: M5K runtime sources currently include TWSE MIS and TAIFEX MIS, but this inventory did not execute them.', '- Conversation context: M5N composes selected latest observation fields, source-health summaries, and canonical context without raw payload handoff.', '- Source health: M5Q stores normalized source-health reports, not raw endpoint payloads.', '- Consumer exposure is traced from code paths; artifact existence alone is not treated as frontend/MCP/conversation exposure.', '', '## Source family inventory', '']
    for s in data['source_families']:
        lines += [f"### {s['source_id']}", '', f"- Evidence status: {s['evidence_status']}", f"- Runtime integrated: {s['runtime_integrated']}; runtime exposure: {', '.join(s['runtime_exposure_status'])}", f"- Evidence files: {', '.join(s['repo_evidence']['files'] + s['repo_evidence']['docs'])}", f"- Current normalized/retained fields: {(', '.join(s['current_normalized_fields']) if s['current_normalized_fields'] else 'none in runtime')}", f"- Raw/source fields known: {(', '.join(s['raw_or_source_fields_available']) if s['raw_or_source_fields_available'] else 'none proven')}", f"- Dropped-field handling: {s['fields_currently_dropped']}", '- Evidence claims:']
        for c in s['evidence_claims']:
            lines.append(f"  - `{c['claim_id']}` ({c['confidence']}): {c['claim']} Evidence: {', '.join(c['evidence_files'])}; symbol/section: {c['evidence_symbol_or_section']}.")
        lines.append('')
    lines += ['## Field lifecycle analysis', '', 'This table answers what raw data is known, what the current parser reads, what normalization independently retains, and what reaches FastAPI/MCP/frontend/conversation context. A `yes` exposure means the current code path returns or renders that field; it is not inferred from artifact presence alone.', '', table(data['field_inventory'], ['source_id', 'raw_field_name', 'raw_field_known', 'current_parser_reads_field', 'current_parser_usage', 'retained_as_independent_normalized_field', 'normalized_field_name', 'derived_normalized_fields', 'exposed_fastapi', 'exposed_mcp', 'exposed_frontend', 'exposed_conversation_context', 'dropped_status', 'dropped_reason_category', 'reintroduction_priority']), '', '## Dropped field decision analysis', '', '`Dropped` does not always mean intentionally rejected. Some fields are dropped because M5K currently normalizes minimal price/freshness; some are known but need unit or semantic validation; some are not dropped at runtime because their source is not integrated at all; and some may be safely deferred to avoid raw payload leakage or trading-like semantics.', '', table(data['dropped_field_decisions'], ['source_id', 'raw_field_name', 'current_lifecycle', 'dropped_reason_category', 'dropped_decision_status', 'reintroduction_priority', 'reintroduction_blockers']), '', '### Fields with no explicit drop decision found', '']
    for d in data['dropped_field_decisions']:
        if d['dropped_decision_status'] == 'no_clear_decision_found':
            lines.append(f"- {d['source_id']}.{d['raw_field_name']}: {d['dropped_reason_detail']}")
    lines += ['', '### Fields intentionally or safely deferred', '']
    for d in data['dropped_field_decisions']:
        if d['reintroduction_priority'] in {'defer', 'M7D_optional', 'M7E_provider_research'} or d['dropped_reason_category'] in {'credential_or_access_limited', 'freshness_or_timestamp_unclear', 'replaced_by_existing_field'}:
            lines.append(f"- {d['source_id']}.{d['raw_field_name']}: {d['dropped_reason_category']} / {d['reintroduction_priority']}.")
    lines += ['', '## Deterministic metrics possible', '', table(data['deterministic_metrics'], ['metric_id', 'required_fields', 'source_family_compatibility', 'current_availability', 'ai_phrasing_allowed', 'ai_phrasing_forbidden']), '', '## AI context expansion strategy', '', '- Facts: expose retained fields with source time, retrieval time, freshness, caveats, and evidence status.', '- Deterministic derived metrics: compute only when required fields are retained and quality flags permit.', '- Bounded summaries: use watchlist counts and differences without preference, ranking, or execution language.', '- AI layer: context-only discussion; no trading semantics.', '', '## Semantic safety rules', '', 'Allowed examples: observed displayed bid depth; bounded watchlist observation; reference-only; delayed or stale; not official realtime SLA.', '', 'Forbidden examples: buy; sell; hold; target price; ranking; guaranteed realtime; support/resistance as fact; institutional/chip flow.', '', '## Recommended M7 roadmap', '']
    for r in data['m7_candidate_roadmap']:
        lines.append(f"- **{r['milestone']}:** {r['scope']}")
    lines += ['', '## README summary proposal', '', 'README now states that the inventory includes validated runtime sources, validated contracts/probes, validated historical workbench evidence, catalogued candidates, and credential-gated providers; it also warns that not every listed family is a validated usable endpoint.', '']
    return '\n'.join(lines)

def main() -> None:
    OUT.mkdir(parents=True, exist_ok=True)
    data = {'schema_version': 'm7_00_data_capability_inventory.v1', 'generated_at_utc': datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ'), 'governance': {'network_calls': False, 'live_observation': False, 'product_behavior_changed': False, 'trading_signal': False, 'recommendation': False}, 'source_taxonomy_summary': SOURCE_TAXONOMY_SUMMARY, 'source_families': source_families, 'field_inventory': field_inventory, 'dropped_field_decisions': dropped_field_decisions, 'deterministic_metrics': deterministic_metrics, 'm7_candidate_roadmap': roadmap}
    validate(data)
    (OUT / 'validated_endpoint_data_capability_inventory.json').write_text(json.dumps(data, ensure_ascii=False, indent=2, sort_keys=True) + '\n', encoding='utf-8')
    write_csv(OUT / 'validated_endpoint_data_capability_matrix.csv', source_families)
    write_csv(OUT / 'validated_endpoint_field_inventory.csv', field_inventory)
    write_csv(OUT / 'ai_context_expansion_planning_matrix.csv', deterministic_metrics)
    (OUT / 'VALIDATED_ENDPOINT_DATA_CAPABILITY_INVENTORY.md').write_text(markdown(data), encoding='utf-8')
    print(f'wrote {OUT.relative_to(ROOT)} with {len(source_families)} source families, {len(field_inventory)} field lifecycle rows, {len(dropped_field_decisions)} dropped-field decisions')
if __name__ == '__main__':
    main()
